69: func tokenRevoked(c *contextmodel.ReqContext, err *auth.TokenRevokedError) {
70: 	if c.IsApiRequest() {
71: 		c.JSON(http.StatusUnauthorized, map[string]any{
72: 			"message": "Token revoked",
